```c
#include <stdio.h>
#include <string.h>

int main() {
    char a[100];
    scanf("%s", a);

    int p = 0, q = 0;
    for (int i = 0; i < strlen(a); i++) {
        if (a[i] == '4') p++;
        if (a[i] == '7') q++;
    }

    if (p > 0 && p >= q) {
        printf("4\n");
    } else if (q > 0) {
        printf("7\n");
    } else {
        printf("-1\n");
    }

    return 0;
}
```

